svg.script:
(() => {
  const details = {
    northwest: { label: "Nord Ovest", value: "€ 4,4 mln", dealers: "14 dealer" },
    northeast: { label: "Nord Est", value: "€ 4,3 mln", dealers: "10 dealer" },
    center: { label: "Centro", value: "€ 4 mln", dealers: "12 dealer" },
    south: { label: "Sud e Isole", value: "€ 3,9 mln", dealers: "12 dealer" }
  };
  const shapes = [...document.querySelectorAll(".macroarea")];
  const tooltip = document.getElementById("map-tooltip");
  const tooltipArea = document.getElementById("tooltip-area");
  const tooltipDealers = document.getElementById("tooltip-dealers");
  const tooltipValue = document.getElementById("tooltip-value");

  function show(shape) {
    const info = details[shape.dataset.area];
    const box = shape.getBBox();
    const x = Math.max(8, Math.min(342, box.x + box.width / 2 - 130));
    const y = Math.max(8, Math.min(680, box.y + box.height / 2 - 118));
    tooltipArea.textContent = info.label;
    tooltipDealers.textContent = info.dealers;
    tooltipValue.textContent = info.value;
    tooltip.setAttribute("transform", `translate(${x} ${y})`);
    tooltip.classList.add("visible");
    shapes.forEach(item => {
      item.classList.toggle("dimmed", item !== shape);
      item.classList.toggle("remote-active", item === shape);
    });
  }

  function hide() {
    tooltip.classList.remove("visible");
    shapes.forEach(item => {
      item.classList.remove("dimmed");
      item.classList.remove("remote-active");
    });
  }

  shapes.forEach(shape => {
    const info = details[shape.dataset.area];
    shape.setAttribute("tabindex", "0");
    shape.setAttribute("aria-label", `${info.label}: ${info.value}, ${info.dealers}`);
    shape.addEventListener("mouseenter", () => show(shape));
    shape.addEventListener("mouseleave", hide);
    shape.addEventListener("focus", () => show(shape));
    shape.addEventListener("blur", hide);
  });

  window.addEventListener("message", event => {
    const message = event.data;
    if (!message || message.type !== "sdf-area-hover") return;
    const shape = shapes.find(item => item.dataset.area === message.area);
    if (!shape) return;
    if (message.active) show(shape);
    else hide();
  });
})();
